type Status = 'new' | 'contacted' | 'followup' | 'closed' | 'dead'
type Tier = 'T1' | 'T2' | 'T3'

interface Lead {
  id: string
  name: string
  type: string
  phone: string
  city: string
  rating: number
  reviews: number
  tier: Tier
  status: Status
}

const STATUS_CONFIG: Record<Status, { label: string; color: string; next: Status }> = {
  new:       { label: 'New',       color: '#334155', next: 'contacted' },
  contacted: { label: 'Contacted', color: '#2563EB', next: 'followup'  },
  followup:  { label: 'Follow Up', color: '#D97706', next: 'closed'    },
  closed:    { label: 'Closed ✓',  color: '#16A34A', next: 'dead'      },
  dead:      { label: 'Dead',      color: '#64748B', next: 'new'       },
}

const TIER_COLOR: Record<Tier, string> = {
  T1: '#EF4444', T2: '#F59E0B', T3: '#6B7280'
}

const STORAGE_KEY = 'rr-leads-v2'

function loadStatuses(): Record<string, Status> {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY) || '{}') }
  catch { return {} }
}

export default function App() {
  const [statuses, setStatuses] = useState<Record<string, Status>>(loadStatuses)
  const [tierFilter, setTierFilter] = useState<Tier | 'All'>('T1')
  const [statusFilter, setStatusFilter] = useState<Status | 'All'>('new')
  const [search, setSearch] = useState('')

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(statuses))
  }, [statuses])

  const leads: Lead[] = useMemo(() => RAW_LEADS.map((l: any) => ({
    ...l,
    status: (statuses[l.id] || l.status) as Status
  })), [statuses])

  const filtered = useMemo(() => leads.filter(l => {
    if (tierFilter !== 'All' && l.tier !== tierFilter) return false
    if (statusFilter !== 'All' && l.status !== statusFilter) return false
    if (search && !l.name.toLowerCase().includes(search.toLowerCase()) && !l.city.toLowerCase().includes(search.toLowerCase())) return false
    return true
  }), [leads, tierFilter, statusFilter, search])

  const counts = useMemo(() => {
    const c: Record<string, number> = { All: 0 }
    for (const s of Object.keys(STATUS_CONFIG)) c[s] = 0
    for (const l of leads) {
      c[l.status] = (c[l.status] || 0) + 1
      c.All++
    }
    return c
  }, [leads])

  const tap = (id: string, current: Status) => {
    const next = STATUS_CONFIG[current].next
    setStatuses(prev => ({ ...prev, [id]: next }))
  }

  const setStatus = (id: string, status: Status) => {
    setStatuses(prev => ({ ...prev, [id]: status }))
  }

  return (
    <div style={{ background: '#0F172A', minHeight: '100vh', color: '#F1F5F9', fontFamily: 'system-ui, -apple-system, sans-serif', maxWidth: 900, margin: '0 auto' }}>

      {/* Header */}
      <div style={{ padding: '16px 16px 0', position: 'sticky', top: 0, background: '#0F172A', zIndex: 50, borderBottom: '1px solid #1E293B' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
          <div>
            <div style={{ fontSize: 11, color: '#EF4444', fontWeight: 700, letterSpacing: 3, textTransform: 'uppercase' }}>RenovationRise</div>
            <div style={{ fontSize: 20, fontWeight: 800, letterSpacing: -0.5 }}>Lead Blaster</div>
          </div>
          <div style={{ textAlign: 'right' }}>
            <div style={{ fontSize: 22, fontWeight: 800, color: '#EF4444' }}>{counts['contacted'] || 0}</div>
            <div style={{ fontSize: 10, color: '#64748B' }}>contacted today</div>
          </div>
        </div>

        {/* Search */}
        <input
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder="Search company or city..."
          style={{ width: '100%', background: '#1E293B', border: '1px solid #334155', borderRadius: 8, padding: '8px 12px', color: '#F1F5F9', fontSize: 14, marginBottom: 10, boxSizing: 'border-box' }}
        />

        {/* Tier tabs */}
        <div style={{ display: 'flex', gap: 6, marginBottom: 8, overflowX: 'auto' }}>
          {(['All', 'T1', 'T2', 'T3'] as const).map(t => (
            <button key={t} onClick={() => setTierFilter(t as any)}
              style={{ flex: 1, padding: '7px 0', borderRadius: 8, border: 'none', cursor: 'pointer', fontWeight: 700, fontSize: 13, background: tierFilter === t ? (t === 'All' ? '#475569' : TIER_COLOR[t as Tier]) : '#1E293B', color: tierFilter === t ? '#FFF' : '#64748B', whiteSpace: 'nowrap' }}>
              {t}
            </button>
          ))}
        </div>

        {/* Status filters */}
        <div style={{ display: 'flex', gap: 5, marginBottom: 10, overflowX: 'auto', paddingBottom: 2 }}>
          {(['All', ...Object.keys(STATUS_CONFIG)] as const).map(s => {
            const active = statusFilter === s
            const cfg = s === 'All' ? null : STATUS_CONFIG[s as Status]
            return (
              <button key={s} onClick={() => setStatusFilter(s as any)}
                style={{ padding: '5px 10px', borderRadius: 20, border: 'none', cursor: 'pointer', fontSize: 11, fontWeight: 700, whiteSpace: 'nowrap', background: active ? (cfg?.color || '#475569') : '#1E293B', color: active ? '#FFF' : '#475569', display: 'flex', alignItems: 'center', gap: 4 }}>
                {cfg?.label || 'All'} <span style={{ background: 'rgba(0,0,0,0.25)', borderRadius: 10, padding: '0 5px', fontSize: 10 }}>{counts[s] || 0}</span>
              </button>
            )
          })}
        </div>
      </div>

      {/* List */}
      <div style={{ padding: '0 0 80px' }}>
        <div style={{ padding: '8px 16px 4px', fontSize: 11, color: '#475569' }}>{filtered.length} leads shown</div>

        {filtered.map(lead => {
          const cfg = STATUS_CONFIG[lead.status]
          return (
            <div key={lead.id} style={{ borderBottom: '1px solid #1E293B', padding: '12px 16px', display: 'flex', alignItems: 'center', gap: 12 }}>

              {/* Tier dot */}
              <div style={{ width: 8, height: 8, borderRadius: '50%', background: TIER_COLOR[lead.tier], flexShrink: 0 }} />

              {/* Info */}
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontWeight: 700, fontSize: 14, color: '#F1F5F9', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{lead.name}</div>
                <div style={{ fontSize: 11, color: '#64748B', marginTop: 2 }}>
                  {lead.city} · {lead.type} · ⭐{lead.rating} ({lead.reviews})
                </div>
                <div style={{ fontSize: 12, color: '#94A3B8', marginTop: 2 }}>{lead.phone}</div>
              </div>

              {/* Status pill — tap to advance */}
              <button
                onClick={() => tap(lead.id, lead.status)}
                style={{ background: cfg.color, color: '#FFF', border: 'none', borderRadius: 20, padding: '6px 14px', fontSize: 12, fontWeight: 700, cursor: 'pointer', whiteSpace: 'nowrap', flexShrink: 0 }}>
                {cfg.label}
              </button>
            </div>
          )
        })}

        {filtered.length === 0 && (
          <div style={{ textAlign: 'center', padding: 60, color: '#334155' }}>No leads match</div>
        )}
      </div>
    </div>
  )
}
